def bsearch_interval(arr: list[list[int]], target: int):
    low = 0
    high = len(arr) - 1

    while low <= high:
        mid = low + (high - low) // 2

        if arr[mid][0] == target:
            return mid
        elif arr[mid][0] < target:
            low = mid + 1
        else:
            high = mid - 1

    return high


class Solution:
    def insert(self, intervals: List[List[int]], newInterval: List[int]) -> List[List[int]]:

        index = bsearch_interval(intervals, newInterval[0])
        start = min(newInterval[0], intervals[index][0])
        end = max(newInterval[1], intervals[index][1])

        length = len(intervals)
        while index < length and intervals[index][0] <= end:
            end = max(end, intervals[index][1])
            intervals.pop(index)
            length -= 1

        intervals.insert(index, [start, end])
        return intervals

